  return profile.name ? profile.name.toUpperCase() : "ANONYMOUS";
}

examples.toCode:
struct UserProfile {
    var name: String?
}

func extractUsername(profile: UserProfile) -> String {
    if let name = profile.name {
        return name.uppercased()
    }
    return "ANONYMOUS"
}
